    i = 0
    n = len(formula)

    while i < n:
        if formula[i] == '(':
            stack.append({})
            i += 1
        elif formula[i] == ')':
            current = stack.pop()
            i += 1
            multiplier = ''
            while i < n and formula[i].isdigit():
                multiplier += formula[i]
                i += 1
            multiplier = int(multiplier) if multiplier else 1
            for element, count in current.items():
                if element not in stack[-1]:
                    stack[-1][element] = 0
                stack[-1][element] += count * multiplier
        elif formula[i].isupper():
            element = formula[i]
            i += 1
            while i < n and formula[i].islower():
                element += formula[i]
                i += 1
            count_str = ''
            while i < n and formula[i].isdigit():
                count_str += formula[i]
                i += 1
            count = int(count_str) if count_str else 1
            if element not in stack[-1]:
                stack[-1][element] = 0
            stack[-1][element] += count

    result = ''
    for element in sorted(stack[0].keys()):
        count = stack[0][element]
        if count > 1:
            result += element + str(count)
        else:
            result += element

    return result
