def atoms(formula):
    n = len(formula)
    i = 0
    stack = [{}]  # stack of count maps; top is current scope

    def parse_count():
        nonlocal i
        start = i
        while i < n and formula[i].isdigit():
            i += 1
        if i == start:
            return 1
        return int(formula[start:i])

    while i < n:
        c = formula[i]
        if c == '(':
            stack.append({})
            i += 1
        elif c == ')':
            i += 1
            mult = parse_count()
            top = stack.pop()
            for name, cnt in top.items():
                stack[-1][name] = stack[-1].get(name, 0) + cnt * mult
        elif c.isupper():
            # element name: uppercase then optional lowercase letters
            start = i
            i += 1
            while i < n and formula[i].islower():
                i += 1
            name = formula[start:i]
            cnt = parse_count()
            stack[-1][name] = stack[-1].get(name, 0) + cnt
        else:
            # malformed input (e.g. stray lowercase/digit at top); skip defensively
            raise ValueError("invalid formula: unexpected character %r at %d" % (c, i))

    if len(stack) != 1:
        raise ValueError("invalid formula: unbalanced parentheses")

    counts = stack[0]
    result = []
    for name in sorted(counts):
        cnt = counts[name]
        result.append(name)
        if cnt > 1:
            result.append(str(cnt))
    return ''.join(result)


