def atoms(formula: str) -> str:
    from collections import defaultdict

    def parse(s, i):
        counts = defaultdict(int)
        while i < len(s):
            if s[i] == '(':
                inner, i = parse(s, i + 1)
                j = i
                while j < len(s) and s[j].isdigit():
                    j += 1
                mult = int(s[i:j]) if j > i else 1
                i = j
                for el, cnt in inner.items():
                    counts[el] += cnt * mult
            elif s[i] == ')':
                return counts, i + 1
            elif s[i].isupper():
                j = i + 1
                while j < len(s) and s[j].islower():
                    j += 1
                el = s[i:j]
                i = j
                k = i
                while k < len(s) and s[k].isdigit():
                    k += 1
                cnt = int(s[i:k]) if k > i else 1
                i = k
                counts[el] += cnt
            else:
                break
        return counts, i

    counts, _ = parse(formula, 0)
    return ''.join(el + (str(counts[el]) if counts[el] > 1 else '') for el in sorted(counts))
