def int_to_roman(n: int) -> str:
    """Converts an integer (1 <= n <= 3999) to its Roman numeral representation."""
    if not (1 <= n <= 3999):
        raise ValueError("Input must be between 1 and 3999.")

    # Define the standard mapping in descending order, including subtractive forms.
    roman_map = [
        (1000, 'M'), (900, 'CM'), (500, 'D'), (400, 'CD'),
        (100, 'C'), (90, 'XC'), (50, 'L'), (40, 'XL'),
        (10, 'X'), (9, 'IX'), (5, 'V'), (4, 'IV'),
        (1, 'I')
    ]

    result = []
    for value, symbol in roman_map:
        while n >= value:
            result.append(symbol)
            n -= value

    return "".join(result)


def roman_to_int(s: str) -> int:
    """Converts a Roman numeral string to its integer equivalent."""
    roman_map = {
        'I': 1, 'V': 5, 'X': 10, 'L': 50, 
        'C': 100, 'D': 500, 'M': 1000
    }

    total = 0
    n = len(s)

    for i in range(n):
        current_val = roman_map[s[i]]

        # Check if there is a next character and if the current value is smaller than the next one (subtractive case)
        if i + 1 < n:
            next_val = roman_map[s[i+1]]
            if current_val < next_val:
                # Subtraction case (e.g., IV = 5 - 1)
                total += (next_val - current_val)
                # Skip the next character since we handled both in this step
                i += 1
                continue

        # Standard additive case
        total += current_val

    return total
